func (i Item) Val(source []byte) []byte {
	if len(i.segments) == 0 {
		return source[i.low:i.high]
	}

	if len(i.segments) == 1 {
		return source[i.segments[0].Low:i.segments[0].High]
	}

	var b bytes.Buffer
	for _, s := range i.segments {
		b.Write(source[s.Low:s.High])
	}
	return b.Bytes()
}
